vector<int> zFunction(const string& s) {
    int n = s.size();
    vector<int> z(n, 0);
    z[0] = n; // Convention: whole string matches itself
    int l = 0, r = 0;
    for (int i = 1; i < n; i++) {
        if (i < r) z[i] = min(r - i, z[i - l]); // Use Z-box
        while (i + z[i] < n && s[z[i]] == s[i + z[i]]) z[i]++; // Extend
        if (i + z[i] > r) { l = i; r = i + z[i]; } // Update Z-box
    }
    return z;
}

// Pattern matching: find all positions of pattern in text
vector<int> zSearch(const string& text, const string& pattern) {
    string s = pattern + '#' + text;
    auto z = zFunction(s);
    int m = pattern.size();
    vector<int> result;
    for (int i = m + 1; i < (int)s.size(); i++)
        if (z[i] == m) result.push_back(i - m - 1);
    return result;
}
