const long long MOD1 = 1e9 + 7, MOD2 = 1e9 + 9;
const long long B1 = 131, B2 = 137;

struct StringHash {
    int n;
    vector<long long> h1, h2, pw1, pw2;
    StringHash(const string& s) : n(s.size()), h1(n+1,0), h2(n+1,0), pw1(n+1,1), pw2(n+1,1) {
        for (int i = 0; i < n; i++) {
            h1[i+1] = (h1[i] * B1 + s[i]) % MOD1;
            h2[i+1] = (h2[i] * B2 + s[i]) % MOD2;
            pw1[i+1] = pw1[i] * B1 % MOD1;
            pw2[i+1] = pw2[i] * B2 % MOD2;
        }
    }
    // Get hash of s[l..r] (0-indexed, inclusive)
    pair<long long,long long> get(int l, int r) {
        long long v1 = (h1[r+1] - h1[l] * pw1[r-l+1] % MOD1 + MOD1*2) % MOD1;
        long long v2 = (h2[r+1] - h2[l] * pw2[r-l+1] % MOD2 + MOD2*2) % MOD2;
        return {v1, v2};
    }
    bool equal(int l1, int r1, int l2, int r2) { return get(l1,r1) == get(l2,r2); }
};
```

兩個字串的最長公共前綴（LCP）：二分長度 k，用哈希 O(1) 比較前 k 個字元是否相等。總複雜度 O(log n)。

```cpp
// LCP of s[l1..] and s[l2..] using StringHash
int lcp(StringHash& h, int l1, int n1, int l2, int n2) {
    int lo = 0, hi = min(n1, n2);
    while (lo < hi) {
        int mid = (lo + hi + 1) / 2;
        if (h.equal(l1, l1+mid-1, l2, l2+mid-1)) lo = mid;
        else hi = mid - 1;
    }
    return lo;
}
```

