int maxXor(int x) {
    int cur = 0, result = 0;
    for (int i = BITS - 1; i >= 0; i--) {
        int want = 1 - ((x >> i) & 1); // Greedy: prefer opposite bit
        if (trie01[cur][want]) { result |= (1 << i); cur = trie01[cur][want]; }
        else cur = trie01[cur][1 - want];
    }
