// Suffix Array (O(n log^2 n) doubling) + Kasai LCP
vector<int> buildSA(const string& s) {
    int n = s.size();
    vector<int> sa(n), rk(n), tmp(n);
    iota(sa.begin(), sa.end(), 0);
    for (int i = 0; i < n; i++) rk[i] = s[i];
    for (int gap = 1; gap < n; gap <<= 1) {
        auto cmp = [&](int a, int b) {
            if (rk[a] != rk[b]) return rk[a] < rk[b];
            int ra = a+gap < n ? rk[a+gap] : -1, rb = b+gap < n ? rk[b+gap] : -1;
            return ra < rb;
        };
        sort(sa.begin(), sa.end(), cmp);
        tmp[sa[0]] = 0;
        for (int i = 1; i < n; i++) tmp[sa[i]] = tmp[sa[i-1]] + (cmp(sa[i-1], sa[i]) ? 1 : 0);
        rk = tmp; if (rk[sa[n-1]] == n-1) break;
    }
    return sa;
}

