bool hasNegativeCycle(int n, const vector<vector<pair<int,int>>>& g) {
    vector<long long> dist(n, 0);
    vector<int> cnt(n, 0); // Edge count to reach this node
    vector<bool> inQueue(n, true);
    queue<int> q;
    for (int i = 0; i < n; i++) q.push(i); // Super source: start from all nodes
    while (!q.empty()) {
        int u = q.front(); q.pop(); inQueue[u] = false;
        for (auto [v, w] : g[u]) {
            if (dist[u] + w < dist[v]) {
                dist[v] = dist[u] + w;
                cnt[v] = cnt[u] + 1;
                if (cnt[v] >= n) return true; // Negative cycle found
                if (!inQueue[v]) { q.push(v); inQueue[v] = true; }
            }
        }
    }
    return false;
}
```

